const data = $input.all()[0].json;

const departmentResults = data.departmentResults || [];

const totalDepartments = departmentResults.length;
const completedDepartments = departmentResults.filter(d => d.status === 'Completed').length;
const failedDepartments = departmentResults.filter(d => d.status === 'Failed').length;

let workflowStatus;
if (totalDepartments > 0 && completedDepartments === totalDepartments) {
  workflowStatus = 'Completed';
} else if (completedDepartments > 0) {
  workflowStatus = 'Partially Completed';
} else {
  workflowStatus = 'Failed';
}

const totalTasks = departmentResults.reduce((sum, d) => sum + (Array.isArray(d.tasksCompleted) ? d.tasksCompleted.length : 0), 0);
const completedTasks = departmentResults
  .filter(d => d.status === 'Completed')
  .reduce((sum, d) => sum + (Array.isArray(d.tasksCompleted) ? d.tasksCompleted.length : 0), 0);

const progressPercentage = totalDepartments > 0 ? Math.round((completedDepartments / totalDepartments) * 100) : 0;

const workflowStartedAt = data.executionStartedAt || null;
const workflowCompletedAt = new Date().toISOString();
const totalExecutionTime = workflowStartedAt ? (new Date(workflowCompletedAt).getTime() - new Date(workflowStartedAt).getTime()) : null;

const timeline = departmentResults.map(d => ({
  department: d.department,
  startedAt: d.startedAt || null,
  completedAt: d.completedAt || null,
  duration: d.duration || null,
  status: d.status
}));

const departmentSummary = departmentResults.map(d => ({
  department: d.department,
  status: d.status,
  completedTasks: Array.isArray(d.tasksCompleted) ? d.tasksCompleted.length : 0,
  duration: d.duration || null
}));

const dashboard = {
  activeWorkflows: workflowStatus === 'Completed' ? 0 : 1,
  pendingWorkflows: 0,
  completedWorkflows: workflowStatus === 'Completed' ? 1 : 0,
  overallProgress: progressPercentage,
  currentWorkflowStatus: workflowStatus,
  lastUpdated: workflowCompletedAt
};

const notifications = departmentResults.map(d => ({
  message: `${d.department} ${d.status === 'Completed' ? 'completed' : String(d.status).toLowerCase()}`,
  department: d.department,
  status: d.status,
  timestamp: d.completedAt || workflowCompletedAt
}));

notifications.push({
  message: `Workflow ${workflowStatus}`,
  department: null,
  status: workflowStatus,
  timestamp: workflowCompletedAt
});

let documentsCount = 0;
if (data.documents) {
  documentsCount = Array.isArray(data.documents) ? data.documents.length : Object.keys(data.documents).length;
}

let statusPhrase;
if (workflowStatus === 'Completed') {
  statusPhrase = 'All departments completed successfully.';
} else if (workflowStatus === 'Partially Completed') {
  statusPhrase = 'Some departments completed while others did not finish.';
} else {
  statusPhrase = 'The workflow did not complete successfully.';
}

const aiResponse = `I analyzed the ${data.workflow || 'requested'} workflow. ${statusPhrase} ${completedTasks} of ${totalTasks} tasks completed across ${completedDepartments} of ${totalDepartments} departments. ${documentsCount} documents generated. Workflow ${workflowStatus.toLowerCase()}.`;

return [{
  json: {
    workflowStatus,
    executionStatistics: {
      totalDepartments,
      completedDepartments,
      failedDepartments,
      totalTasks,
      completedTasks,
      progressPercentage,
      totalExecutionTime,
      workflowStartedAt,
      workflowCompletedAt
    },
    timeline,
    departmentSummary,
    dashboard,
    notifications,
    aiResponse
  }
}];
